"use client";

import { useEffect, useState } from "react";
import { useCurrentUserRole } from "@/hooks/use-current-user-role";

export function Preloader() {
  const { loading: authLoading } = useCurrentUserRole();
  const [windowLoaded, setWindowLoaded] = useState(false);
  const [show, setShow] = useState(true);
  const [fadeOut, setFadeOut] = useState(false);

  useEffect(() => {
    if (typeof window !== "undefined") {
      if (document.readyState === "complete") {
        setWindowLoaded(true);
      } else {
        const onWindowLoad = () => setWindowLoaded(true);
        window.addEventListener("load", onWindowLoad);
        return () => window.removeEventListener("load", onWindowLoad);
      }
    }
  }, []);

  useEffect(() => {
    // We want to wait until both Firebase auth is resolved AND the window is fully loaded
    if (!authLoading && windowLoaded) {
      // Add a small delay so it doesn't flash too abruptly if cache is fast
      const timer = setTimeout(() => {
        setFadeOut(true);
        // Wait for CSS transition to complete before unmounting
        setTimeout(() => setShow(false), 500); 
      }, 400);
      return () => clearTimeout(timer);
    }
  }, [authLoading, windowLoaded]);

  if (!show) return null;

  return (
    <div
      className={`fixed inset-0 z-[100] flex flex-col items-center justify-center bg-background transition-opacity duration-700 ${
        fadeOut ? "opacity-0 pointer-events-none" : "opacity-100"
      }`}
    >
      <div className="relative flex flex-col items-center justify-center">
        {/* Professional spinning ring around the logo */}
        <div className="absolute -inset-3 rounded-full border-[3px] border-muted border-t-primary animate-spin" />
        
        {/* Base64 Logo for instant loading */}
        <img
          src="data:image/jpeg;base64,"
          alt="Beacon Logo"
          className="relative h-24 w-24 rounded-full object-cover shadow-lg z-10"
        />
      </div>
      <p className="mt-4 text-foreground font-sans font-bold text-2xl tracking-widest">
        Beacon
      </p>
    </div>
  );
}
